import React, { useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import toast from 'react-hot-toast';
import { Upload, MapPin, Camera, X } from 'lucide-react';

const SEVERITIES = [
  { value:'low',      label:'Low',      color:'var(--green)',  desc:'Minor crack or small pothole' },
  { value:'medium',   label:'Medium',   color:'var(--yellow)', desc:'Noticeable damage, caution needed' },
  { value:'high',     label:'High',     color:'var(--accent)', desc:'Large pothole or significant damage' },
  { value:'critical', label:'Critical', color:'var(--red)',    desc:'Dangerous — immediate action needed' },
];

const HAZARD_TYPES = [
  { value:'pothole',      label:'Pothole' },
  { value:'crack',        label:'Road Crack' },
  { value:'flooding',     label:'Road Flooding' },
  { value:'debris',       label:'Debris / Obstruction' },
  { value:'missing_sign', label:'Missing / Damaged Sign' },
  { value:'other',        label:'Other' },
];

export default function SubmitReport() {
  const navigate = useNavigate();
  const fileRef = useRef();
  const [form, setForm] = useState({
    title:'', description:'', location_text:'',
    latitude:'', longitude:'', severity:'medium', hazard_type:'pothole'
  });
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const [locLoading, setLocLoading] = useState(false);

  const handleImage = (file) => {
    if (!file) return;
    if (!file.type.startsWith('image/')) return toast.error('Please select an image file');
    if (file.size > 10*1024*1024) return toast.error('Image must be under 10MB');
    setImage(file);
    const reader = new FileReader();
    reader.onload = e => setPreview(e.target.result);
    reader.readAsDataURL(file);
  };

  const getLocation = () => {
    if (!navigator.geolocation) return toast.error('Geolocation not supported');
    setLocLoading(true);
    navigator.geolocation.getCurrentPosition(
      pos => {
        setForm(f => ({ ...f, latitude: pos.coords.latitude.toFixed(6), longitude: pos.coords.longitude.toFixed(6) }));
        toast.success('Location captured!');
        setLocLoading(false);
      },
      () => { toast.error('Could not get location'); setLocLoading(false); }
    );
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.title.trim()) return toast.error('Title is required');
    if (!form.location_text.trim()) return toast.error('Location is required');

    setLoading(true);
    try {
      const fd = new FormData();
      Object.entries(form).forEach(([k,v]) => v && fd.append(k, v));
      if (image) fd.append('image', image);
      await axios.post('/api/reports', fd, { headers:{'Content-Type':'multipart/form-data'} });
      toast.success('Report submitted successfully!');
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Submission failed');
    } finally { setLoading(false); }
  };

  return (
    <div className="page-container fade-up" style={{ maxWidth:700 }}>
      <div style={{ marginBottom:28 }}>
        <h1 style={{ fontSize:26, marginBottom:6 }}>Report a Road Hazard</h1>
        <p style={{ color:'var(--text-muted)' }}>Provide as much detail as possible to help authorities respond faster.</p>
      </div>

      <form onSubmit={handleSubmit} style={{ display:'flex', flexDirection:'column', gap:24 }}>
        {/* Basic Info */}
        <div className="card" style={{ display:'flex', flexDirection:'column', gap:16 }}>
          <h3 style={{ fontSize:15, color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.06em' }}>Hazard Details</h3>
          <div className="form-group">
            <label className="form-label">Title *</label>
            <input className="form-input" placeholder="e.g. Large pothole on MG Road near flyover"
              value={form.title} onChange={e=>setForm({...form,title:e.target.value})} required/>
          </div>
          <div className="form-group">
            <label className="form-label">Description</label>
            <textarea className="form-input" rows={3} placeholder="Describe the damage in detail…"
              value={form.description} onChange={e=>setForm({...form,description:e.target.value})} style={{ resize:'vertical' }}/>
          </div>
          <div className="form-group">
            <label className="form-label">Hazard Type *</label>
            <select className="form-input" value={form.hazard_type} onChange={e=>setForm({...form,hazard_type:e.target.value})}>
              {HAZARD_TYPES.map(h => <option key={h.value} value={h.value}>{h.label}</option>)}
            </select>
          </div>
        </div>

        {/* Severity */}
        <div className="card">
          <h3 style={{ fontSize:15, color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.06em', marginBottom:14 }}>Severity Level *</h3>
          <div style={{ display:'grid', gridTemplateColumns:'repeat(2,1fr)', gap:10 }}>
            {SEVERITIES.map(s => (
              <label key={s.value} style={{
                display:'flex', alignItems:'flex-start', gap:10, padding:'12px 14px',
                borderRadius:10, border:`2px solid ${form.severity===s.value ? s.color : 'var(--border)'}`,
                background: form.severity===s.value ? `${s.color}15` : 'var(--bg)',
                cursor:'pointer', transition:'all 0.15s',
              }}>
                <input type="radio" name="severity" value={s.value}
                  checked={form.severity===s.value}
                  onChange={e=>setForm({...form,severity:e.target.value})}
                  style={{ marginTop:2, accentColor:s.color }}/>
                <div>
                  <div style={{ fontWeight:600, fontSize:14, color:s.color }}>{s.label}</div>
                  <div style={{ fontSize:12, color:'var(--text-muted)', marginTop:2 }}>{s.desc}</div>
                </div>
              </label>
            ))}
          </div>
        </div>

        {/* Location */}
        <div className="card" style={{ display:'flex', flexDirection:'column', gap:14 }}>
          <h3 style={{ fontSize:15, color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.06em' }}>Location</h3>
          <div className="form-group">
            <label className="form-label">Location Description *</label>
            <input className="form-input" placeholder="e.g. MG Road, near Inorbit Mall, Hyderabad"
              value={form.location_text} onChange={e=>setForm({...form,location_text:e.target.value})} required/>
          </div>
          <div style={{ display:'flex', gap:10, alignItems:'flex-end' }}>
            <div className="form-group" style={{ flex:1 }}>
              <label className="form-label">Latitude</label>
              <input className="form-input" type="number" step="any" placeholder="17.3850"
                value={form.latitude} onChange={e=>setForm({...form,latitude:e.target.value})}/>
            </div>
            <div className="form-group" style={{ flex:1 }}>
              <label className="form-label">Longitude</label>
              <input className="form-input" type="number" step="any" placeholder="78.4867"
                value={form.longitude} onChange={e=>setForm({...form,longitude:e.target.value})}/>
            </div>
            <button type="button" className="btn btn-ghost" onClick={getLocation} disabled={locLoading} style={{ flexShrink:0, height:42 }}>
              <MapPin size={15}/> {locLoading ? 'Getting…' : 'Use GPS'}
            </button>
          </div>
        </div>

        {/* Photo Upload */}
        <div className="card">
          <h3 style={{ fontSize:15, color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.06em', marginBottom:14 }}>Photo Evidence</h3>
          {preview ? (
            <div style={{ position:'relative', borderRadius:10, overflow:'hidden' }}>
              <img src={preview} alt="Preview" style={{ width:'100%', maxHeight:280, objectFit:'cover', borderRadius:10 }}/>
              <button type="button"
                style={{ position:'absolute', top:10, right:10, background:'rgba(0,0,0,0.7)', border:'none', borderRadius:'50%', width:32, height:32, display:'flex', alignItems:'center', justifyContent:'center', color:'#fff', cursor:'pointer' }}
                onClick={()=>{ setImage(null); setPreview(null); }}>
                <X size={16}/>
              </button>
            </div>
          ) : (
            <div onClick={()=>fileRef.current.click()}
              onDrop={e=>{e.preventDefault();handleImage(e.dataTransfer.files[0]);}}
              onDragOver={e=>e.preventDefault()}
              style={{ border:'2px dashed var(--border-light)', borderRadius:12, padding:'40px 20px', textAlign:'center', cursor:'pointer', background:'var(--bg)' }}
              onMouseEnter={e=>e.currentTarget.style.borderColor='var(--accent)'}
              onMouseLeave={e=>e.currentTarget.style.borderColor='var(--border-light)'}>
              <Camera size={32} color="var(--text-faint)" style={{ marginBottom:10 }}/>
              <p style={{ fontSize:14, color:'var(--text-muted)', marginBottom:4 }}>Click to upload or drag & drop</p>
              <p style={{ fontSize:12, color:'var(--text-faint)' }}>PNG, JPG, WEBP up to 10MB</p>
              <input ref={fileRef} type="file" accept="image/*" style={{ display:'none' }} onChange={e=>handleImage(e.target.files[0])}/>
            </div>
          )}
        </div>

        <div style={{ display:'flex', gap:12, justifyContent:'flex-end' }}>
          <button type="button" className="btn btn-ghost" onClick={()=>navigate('/dashboard')}>Cancel</button>
          <button type="submit" className="btn btn-primary" style={{ padding:'10px 28px' }} disabled={loading}>
            <Upload size={15}/> {loading ? 'Submitting…' : 'Submit Report'}
          </button>
        </div>
      </form>
    </div>
  );
}
